import { useCallback } from 'react';
import { getClientNRC } from '../../../../hooks/useSelectors';
import { checkHasRedeemed as checkHasRedeemedService, markAsRedeemed as markAsRedeemedService } from '../services';
import { useRootStore } from '../..';
import { PermissionStatus } from '../models';

export function usePermission() {
  const accountId = getClientNRC();

  const { hasRedeemed, status } = useRootStore((state) => state.permission);

  const { setStatus } = useRootStore((state) => state.permissionActions);

  const isLoading = status === PermissionStatus.LOADING;
  const isError = status === PermissionStatus.ERROR;

  const checkHasRedeemed = useCallback(
    async ({
      showLoading = false,
      forceRefresh = false,
    }: { showLoading?: boolean; forceRefresh?: boolean } = {}): Promise<boolean> => {
      if (hasRedeemed !== null && !forceRefresh) {
        return hasRedeemed;
      }

      if (!accountId) {
        throw new Error('Expected accountId to be defined.');
      }

      if (showLoading) {
        setStatus(PermissionStatus.LOADING);
      }

      return checkHasRedeemedService(accountId);
    },
    [accountId, hasRedeemed, setStatus]
  );

  const markAsRedeemed = useCallback(async (): Promise<boolean> => {
    if (!accountId) {
      return false;
    }

    return markAsRedeemedService(accountId);
  }, [accountId]);

  return {
    hasRedeemed,
    isLoading,
    isError,
    checkHasRedeemed,
    markAsRedeemed,
  };
}

