import { logoutAppCardDebts } from '@semparar/mf-app-cardebts';
import { cleanFintechCardPlaceReducers } from '@semparar/mf-app-fintech-card-place';
import { cleanFintechOnboardingReducers } from '@semparar/mf-app-fintech-onboarding/src/redux/sagas/logout';
import { PartialBlockActions } from '@semparar/mf-app-user';
import { NewVehiclesActions } from '@semparar/mf-app-vehicles';

import { homeService } from '~/modules/homeService';
import { useRootStore } from '~/store';

import { ActionCreators as Actions } from '../actions';
import Store from '../store';

export const logout = async () => {
  Store.dispatch(PartialBlockActions.cleanPartialBlock());

  await logoutAppCardDebts();

  // RESET extrato pos //

  Store.dispatch(Actions?.getInvoicesTicketUpdate(false));
  Store.dispatch(Actions?.PostPaidClear());
  Store.dispatch(Actions?.vehiclesColorsResponse());
  Store.dispatch(Actions?.vehiclesModelsClean());
  Store.dispatch(Actions?.vehiclesModelsResponse([]));
  Store.dispatch(Actions?.taxValueResponse(''));
  Store.dispatch(Actions?.TicketPosSuccess(''));
  Store.dispatch(Actions?.TicketPosCloseModal());
  Store.dispatch(Actions?.clearTransactionData());
  Store.dispatch(Actions?.ufListResponse([]));
  Store.dispatch(Actions?.validatePlateResponse([]));
  Store.dispatch(Actions?.validatePlateResponse([]));
  Store.dispatch(Actions?.vehiclesConductorResponse([]));
  Store.dispatch(Actions?.vehiclesClear());
  Store.dispatch(
    Actions?.getInvoicesTicketHasticket({
      hasTicket: false,
    })
  );

  // Reset brandsCar //
  // sao 3 brands car confirmar dps ///
  Store.dispatch(Actions?.cardsBrandsResponse([]));

  // create order reducer //
  Store.dispatch(Actions?.clearOrder());

  // RESET extrato pre //
  Store.dispatch(Actions?.PreExtractClear());
  Store.dispatch(Actions?.PreExtractClearSaldo());
  Store.dispatch(Actions?.PreExtractClearProduct());
  Store.dispatch(Actions?.invoicePreClear());

  // RESET EXTRATO TRIO //
  Store.dispatch(Actions?.TrioResumeClear());
  Store.dispatch(Actions?.trioCardsClear());

  // fuel //
  Store.dispatch(Actions?.vehiclesFuelsResponse([]));

  // log pause //
  Store.dispatch(Actions?.clearLogPauses());

  // RESET LIMITS DRIVE THRU
  Store.dispatch(Actions?.DriveThruFilterSuccess(''));
  Store.dispatch(Actions?.DriveThruLimitsSuccess(''));

  // RESET LIMITS REFUEL
  Store.dispatch(Actions?.RefuelLimitsFilterSuccess(''));
  Store.dispatch(Actions?.RefuelLimitsSuccess(''));

  Store.dispatch(Actions?.clearSearchAddress());

  // zapay
  Store.dispatch(Actions?.clearZapay());

  // pix
  Store.dispatch(Actions?.clearPix());
  // sppay
  Store.dispatch(Actions?.clearSppay());

  // EXTRACT DETAILS
  Store.dispatch(Actions?.clearDetailsExtract());

  // CASHBACK
  Store.dispatch(Actions?.clearCashback());

  // SECURITY
  Store.dispatch(Actions?.clearSecurity());

  Store.dispatch(Actions?.clearMarketplaceToken());

  Store.dispatch(Actions?.refuelClearData());

  // SESSION
  Store.dispatch(Actions?.clearSession());

  // INSURANCE
  Store.dispatch(Actions?.updateMicroInsuranceLogout());
  Store.dispatch(Actions?.clearPlateAutoComplete());

  // reset Refresh Extract
  Store.dispatch(Actions?.clearRefreshExtract());

  cleanFintechOnboardingReducers<typeof Actions, typeof Store>(Actions, Store);
  cleanFintechCardPlaceReducers<typeof Actions, typeof Store>(Actions, Store);

  Store.dispatch(NewVehiclesActions?.vehiclesClearData());

  Store.dispatch(Actions?.generateTicketAgreementClean());
  Store.dispatch(Actions?.getInvoicesTicketClear());
  Store.dispatch(Actions?.bankReturnClear());

  // FINANCE
  Store.dispatch(Actions?.financeClosedInvoicesItemsClear());
  Store.dispatch(Actions?.financeInvoicesClear());
  Store.dispatch(Actions?.financeInvoicesItemsClear());
  Store.dispatch(Actions?.financeRealBalanceClear());
  Store.dispatch(Actions?.financeRechargeItemsClear());
  Store.dispatch(Actions?.financeSummarizedItemsClear());

  Store.dispatch(Actions?.clearUpdatedDebts());

  Store.dispatch(Actions?.clearChatinApp());

  homeService.removeData();

  useRootStore.getState().chatActions.resetChat();
};

