import { CommonActions } from '@react-navigation/native';
import { api } from '@semparar/mf-app-user';
import { expectSaga } from 'redux-saga-test-plan';
import { throwError } from 'redux-saga-test-plan/providers';
import { call, put } from 'redux-saga/effects';

import { Creators as ExampleActions } from '../../../../src/redux/ducks/example';
import { failureMessage } from '../../../../src/redux/sagas/example/functions';
import { exampleRequest } from '../../../../src/redux/sagas/example/index';
import { navigatorRef } from '../../../../src/routes/navigation';

jest.mock('@semparar/mf-app-user', () => ({
  api: {
    post: jest.fn(),
  },
}));

jest.mock('../../../../src/redux/sagas/example/functions', () => ({
  failureMessage: jest.fn(),
}));

const dispatchMock = jest.fn();
navigatorRef.current = { dispatch: dispatchMock } as any;

describe('exampleRequest saga', () => {
  const action = {
    data: { test1: 'a', test2: 'b' },
  };

  it('should dispatch success and navigate on success response', () => {
    const mockResponse = {
      data: {
        status: { codigoRetorno: 0 },
        dados: { mensagem: 'Tudo certo!' },
      },
    };

    return expectSaga(exampleRequest, action)
      .provide([[call(api.post, '/example', action.data), mockResponse]])
      .put(ExampleActions.success('Tudo certo!'))
      .run()
      .then(() => {
        expect(dispatchMock).toHaveBeenCalledWith(
          CommonActions.reset({
            index: 0,
            routes: [{ name: 'SuccessExample' }],
          }),
        );
      });
  });

  it('should dispatch fail and call failureMessage on non-zero retorno', () => {
    const mockResponse = {
      data: {
        status: { codigoRetorno: 1 },
      },
    };

    return expectSaga(exampleRequest, action)
      .provide([[call(api.post, '/example', action.data), mockResponse]])
      .put(ExampleActions.fail())
      .run()
      .then(() => {
        expect(failureMessage).toHaveBeenCalled();
      });
  });

  it('should dispatch fail and call failureMessage on exception', () => {
    return expectSaga(exampleRequest, action)
      .provide([
        [
          call(api.post, '/example', action.data),
          throwError(new Error('API error')),
        ],
      ])
      .put(ExampleActions.fail())
      .run()
      .then(() => {
        expect(failureMessage).toHaveBeenCalled();
      });
  });
});

