import { pointsReducer, Types, PointsActions, initialState } from '../../../src/redux/ducks/points';
import { PointsExtractData } from '../../../src/redux/ducks/points';

describe('Points Reducer', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('REQUEST_BALANCE', () => {
    it('should handle REQUEST_BALANCE action', () => {
      const action = PointsActions.requestPointsBalance();
      const state = pointsReducer(initialState, action);

      expect(state).toEqual({
        ...initialState,
        isLoadingBalance: true,
        isErrorBalance: false,
      });
    });
  });

  describe('SUCCESS_BALANCE', () => {
    it('should handle SUCCESS_BALANCE action with points', () => {
      const action = PointsActions.successPointsBalance(5000);
      const state = pointsReducer(initialState, action);

      expect(state).toEqual({
        ...initialState,
        points: 5000,
        isLoadingBalance: false,
        isErrorBalance: false,
      });
    });

    it('should handle SUCCESS_BALANCE action without points', () => {
      const action = PointsActions.successPointsBalance(undefined);
      const state = pointsReducer(initialState, action);

      expect(state).toEqual({
        ...initialState,
        points: undefined,
        isLoadingBalance: false,
        isErrorBalance: false,
      });
    });
  });

  describe('FAILED_BALANCE', () => {
    it('should handle FAILED_BALANCE action', () => {
      const action = PointsActions.failedPointsBalance();
      const state = pointsReducer(initialState, action);

      expect(state).toEqual({
        ...initialState,
        isLoadingBalance: false,
        isErrorBalance: true,
      });
    });
  });

  describe('REQUEST_PRODUCTS', () => {
    it('should handle REQUEST_PRODUCTS action', () => {
      const action = PointsActions.requestPointsProducts();
      const state = pointsReducer(initialState, action);

      expect(state).toEqual({
        ...initialState,
        isLoadingProducts: true,
        isErrorProducts: false,
      });
    });
  });

  describe('SUCCESS_PRODUCTS', () => {
    it('should handle SUCCESS_PRODUCTS action', () => {
      const products = [
        {
          name: 'Product 1',
          redemptionOrigin: 'origin1',
          conversionFactor: 1.5,
        },
      ];
      const action = PointsActions.successPointsProducts(products);
      const state = pointsReducer(initialState, action);

      expect(state).toEqual({
        ...initialState,
        products,
        isLoadingProducts: false,
        isErrorProducts: false,
      });
    });
  });

  describe('FAILED_PRODUCTS', () => {
    it('should handle FAILED_PRODUCTS action', () => {
      const action = PointsActions.failedPointsProducts();
      const state = pointsReducer(initialState, action);

      expect(state).toEqual({
        ...initialState,
        isLoadingProducts: false,
        isErrorProducts: true,
      });
    });
  });

  describe('REQUEST_EXTRACT', () => {
    it('should handle REQUEST_EXTRACT action', () => {
      const action = PointsActions.requestPointsExtract();
      const state = pointsReducer(initialState, action);

      expect(state).toEqual({
        ...initialState,
        isLoadingExtract: true,
        isErrorExtract: false,
      });
    });
  });

  describe('SUCCESS_EXTRACT', () => {
    it('should handle SUCCESS_EXTRACT action', () => {
      const extractData: PointsExtractData = {
        transactions: [
          {
            id: '1',
            date: '2024-01-15T10:30:00Z',
            description: 'Transaction 1',
            type: 'RECEIVED',
            amount: 1000,
            currencyValue: 0,
            icon: 'icon-test',
            details: {
              provider: 'test',
              extraInfo: 'Test info',
              fields: [],
            },
          },
        ],
        expiringPoints: [{ amount: 500, expirationDate: '2024-01-20T10:30:00Z' }],
        transactionsFilters: {
          periods: [{ value: 30, label: 'Últimos 30 dias' }],
          types: [{ value: 'RECEIVED', label: 'Ganhos' }],
        },
        expiringFilters: {
          periods: [{ value: 30, label: 'Próximos 30 dias' }],
        },
      };

      const action = PointsActions.successPointsExtract(extractData);
      const state = pointsReducer(initialState, action);

      expect(state).toEqual({
        ...initialState,
        extractData,
        isLoadingExtract: false,
        isErrorExtract: false,
      });
    });
  });

  describe('FAILED_EXTRACT', () => {
    it('should handle FAILED_EXTRACT action', () => {
      const action = PointsActions.failedPointsExtract();
      const state = pointsReducer(initialState, action);

      expect(state).toEqual({
        ...initialState,
        isLoadingExtract: false,
        isErrorExtract: true,
      });
    });
  });

  describe('CLEAR', () => {
    it('should handle CLEAR action', () => {
      const currentState = {
        ...initialState,
        points: 5000,
        extractData: {} as PointsExtractData,
        isLoadingBalance: true,
        isErrorBalance: true,
      };

      const action = PointsActions.clear();
      const state = pointsReducer(currentState, action);

      expect(state).toEqual(initialState);
    });
  });

  describe('Multiple actions', () => {
    it('should handle multiple actions in sequence', () => {
      let state = pointsReducer(initialState, PointsActions.requestPointsBalance());
      expect(state.isLoadingBalance).toBe(true);

      state = pointsReducer(state, PointsActions.successPointsBalance(3000));
      expect(state.points).toBe(3000);
      expect(state.isLoadingBalance).toBe(false);

      state = pointsReducer(state, PointsActions.requestPointsExtract());
      expect(state.isLoadingExtract).toBe(true);

      const extractData: PointsExtractData = {
        transactions: [],
        expiringPoints: [],
        transactionsFilters: { periods: [], types: [] },
        expiringFilters: { periods: [] },
      };

      state = pointsReducer(state, PointsActions.successPointsExtract(extractData));
      expect(state.extractData).toEqual(extractData);
      expect(state.isLoadingExtract).toBe(false);
    });

    it('should handle error states correctly', () => {
