import { useRootStore } from '~/store';
import { cardPlaceLogoutHandler } from '../../../src/redux/sagas/logout';

jest.mock('~/store', () => ({
  useRootStore: {
    getState: jest.fn(),
  },
}));

describe('cardPlaceLogoutHandler', () => {
  let consoleErrorSpy: jest.SpyInstance;

  beforeEach(() => {
    jest.clearAllMocks();
    consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation(() => {});
  });

  afterEach(() => {
    consoleErrorSpy.mockRestore();
  });

  it('should call reset on all actions objects in the store', () => {
    const mockResetParameter = jest.fn();
    const mockResetPermission = jest.fn();
    const mockResetAdditionalCard = jest.fn();

    const mockState = {
      parameterPointsProgram: { status: 'success', data: [] },
      parameterPointsProgramActions: { reset: mockResetParameter },
      permission: { hasRedeemed: true, status: 'success' },
      permissionActions: { reset: mockResetPermission },
      additionalCard: { name: 'Test', age: 25 },
      additionalCardActions: { reset: mockResetAdditionalCard },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    expect(mockResetParameter).toHaveBeenCalledTimes(1);
    expect(mockResetPermission).toHaveBeenCalledTimes(1);
    expect(mockResetAdditionalCard).toHaveBeenCalledTimes(1);
  });

  it('should not call reset on state objects (non-Actions)', () => {
    const mockReset = jest.fn();

    const mockState = {
      parameterPointsProgram: { reset: mockReset },
      parameterPointsProgramActions: { reset: jest.fn() },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    expect(mockReset).not.toHaveBeenCalled();
  });

  it('should log error if Actions object is missing reset method', () => {
    const mockState = {
      someActions: { notReset: jest.fn() },
      parameterPointsProgramActions: { reset: jest.fn() },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    expect(consoleErrorSpy).toHaveBeenCalledWith(
      'useRootStore.getState().someActions is missing a "reset" action.'
    );
  });

  it('should handle errors during reset gracefully', () => {
    const mockResetThrowing = jest.fn().mockImplementation(() => {
      throw new Error('Reset failed');
    });
    const mockResetWorking = jest.fn();

    const mockState = {
      failingActions: { reset: mockResetThrowing },
      workingActions: { reset: mockResetWorking },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    expect(mockResetThrowing).toHaveBeenCalled();
    expect(mockResetWorking).toHaveBeenCalled();
    expect(consoleErrorSpy).toHaveBeenCalledWith(
      'Failed to run failingActions.reset():',
      expect.any(Error)
    );
  });

  it('should skip Actions objects in IGNORE_CACHE_CLEAR set', () => {
    // Note: IGNORE_CACHE_CLEAR is currently empty, but this tests the mechanism
    const mockReset = jest.fn();

    const mockState = {
      normalActions: { reset: mockReset },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    expect(mockReset).toHaveBeenCalled();
  });

  it('should handle Actions object with null reset method', () => {
    const mockState = {
      nullResetActions: { reset: null },
      validActions: { reset: jest.fn() },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    expect(consoleErrorSpy).toHaveBeenCalledWith(
      'useRootStore.getState().nullResetActions is missing a "reset" action.'
    );
  });

  it('should handle Actions object with undefined reset method', () => {
    const mockState = {
      undefinedResetActions: { reset: undefined },
      validActions: { reset: jest.fn() },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    expect(consoleErrorSpy).toHaveBeenCalledWith(
      'useRootStore.getState().undefinedResetActions is missing a "reset" action.'
    );
  });

  it('should only process objects ending with "Actions"', () => {
    const mockResetActions = jest.fn();
    const mockResetState = jest.fn();
    const mockResetOther = jest.fn();

    const mockState = {
      myActions: { reset: mockResetActions },
      myState: { reset: mockResetState },
      myHelper: { reset: mockResetOther },
      anotherActionsObject: { reset: jest.fn() },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    expect(mockResetActions).toHaveBeenCalled();
    expect(mockResetState).not.toHaveBeenCalled();
    expect(mockResetOther).not.toHaveBeenCalled();
  });

  it('should handle empty store state', () => {
    const mockState = {};

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    expect(() => cardPlaceLogoutHandler()).not.toThrow();
  });

  it('should validate reset is a function before calling', () => {
    const mockState = {
      stringResetActions: { reset: 'not a function' },
      numberResetActions: { reset: 123 },
      validActions: { reset: jest.fn() },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    expect(consoleErrorSpy).toHaveBeenCalledWith(
      'useRootStore.getState().stringResetActions is missing a "reset" action.'
    );
    expect(consoleErrorSpy).toHaveBeenCalledWith(
      'useRootStore.getState().numberResetActions is missing a "reset" action.'
    );
  });

  it('should handle all current Zustand slices correctly', () => {
    const mockResetParameter = jest.fn();
    const mockResetPermission = jest.fn();
    const mockResetAdditionalCard = jest.fn();

    // Simulate actual store structure
    const mockState = {
      // State objects (should not be reset)
      parameterPointsProgram: {
        status: 'success',
        data: [{ category: 'test' }],
      },
      permission: {
        hasRedeemed: true,
        status: 'success',
      },
      additionalCard: {
        name: 'John Doe',
        age: 30,
      },

      // Actions objects (should be reset)
      parameterPointsProgramActions: {
        setStatus: jest.fn(),
        setData: jest.fn(),
        reset: mockResetParameter,
      },
      permissionActions: {
        setStatus: jest.fn(),
        setHasRedeemed: jest.fn(),
        reset: mockResetPermission,
      },
      additionalCardActions: {
        setName: jest.fn(),
        setAge: jest.fn(),
        reset: mockResetAdditionalCard,
      },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    // Verify only Actions objects were reset
    expect(mockResetParameter).toHaveBeenCalledTimes(1);
    expect(mockResetPermission).toHaveBeenCalledTimes(1);
    expect(mockResetAdditionalCard).toHaveBeenCalledTimes(1);

    // Verify no errors were logged
    expect(consoleErrorSpy).not.toHaveBeenCalled();
  });

  it('should continue processing remaining slices if one fails', () => {
    const mockResetFirst = jest.fn().mockImplementation(() => {
      throw new Error('First reset failed');
    });
    const mockResetSecond = jest.fn();
    const mockResetThird = jest.fn().mockImplementation(() => {
      throw new Error('Third reset failed');
    });
    const mockResetFourth = jest.fn();

    const mockState = {
      firstActions: { reset: mockResetFirst },
      secondActions: { reset: mockResetSecond },
      thirdActions: { reset: mockResetThird },
      fourthActions: { reset: mockResetFourth },
    };

    (useRootStore.getState as jest.Mock).mockReturnValue(mockState);

    cardPlaceLogoutHandler();

    // All should be called despite errors
    expect(mockResetFirst).toHaveBeenCalled();
    expect(mockResetSecond).toHaveBeenCalled();
    expect(mockResetThird).toHaveBeenCalled();
    expect(mockResetFourth).toHaveBeenCalled();

    // Errors should be logged
    expect(consoleErrorSpy).toHaveBeenCalledTimes(2);
  });
});

