import { cardPlaceStoreCleanup, IGNORE_CACHE_CLEAR } from '../../../../src/newArch/store/utils/cleanup';

jest.mock('~/store', () => ({
  useRootStore: require('../../../__mocks__/test-store').useTestRootStore,
}));

import { useTestRootStore } from '../../../__mocks__/test-store';

describe('cardPlaceStoreCleanup', () => {
  let consoleErrorSpy: jest.SpyInstance;
  let resetMocks: Record<string, jest.Mock>;

  beforeEach(() => {
    jest.clearAllMocks();
    IGNORE_CACHE_CLEAR.clear();

    consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation(() => {});

    const state = useTestRootStore.getState();
    resetMocks = {};

    Object.entries(state).forEach(([key, element]) => {
      if (key.endsWith('Actions')) {
        const actions = element as any;
        if (actions && typeof actions === 'object' && 'reset' in actions) {
          resetMocks[key] = jest.fn();
          (actions as any).reset = resetMocks[key];
        }
      }
    });
  });

  afterEach(() => {
    consoleErrorSpy.mockRestore();
  });

  describe('Normal operation', () => {
    it('should call reset() on all action objects', () => {
      // Arrange
      const state = useTestRootStore.getState();
      const actionKeys = Object.keys(state).filter((key) => key.endsWith('Actions'));

      // Act
      cardPlaceStoreCleanup();

      // Assert
      expect(actionKeys.length).toBeGreaterThan(0); // Ensure we have actions to test
      actionKeys.forEach((key) => {
        expect(resetMocks[key]).toHaveBeenCalledTimes(1);
      });
    });

    it('should not call reset() on state objects', () => {
      // Arrange
      const state = useTestRootStore.getState();
      const stateKeys = Object.keys(state).filter((key) => !key.endsWith('Actions'));

      // Create spies on state objects (if they have reset methods, which they shouldn't)
      stateKeys.forEach((key) => {
        const stateObj = (state as any)[key];
        if (stateObj && typeof stateObj === 'object' && 'reset' in stateObj) {
          jest.spyOn(stateObj, 'reset');
        }
      });

      // Act
      cardPlaceStoreCleanup();

      // Assert
      stateKeys.forEach((key) => {
        const stateObj = (state as any)[key];
        if (stateObj && typeof stateObj === 'object' && 'reset' in stateObj) {
          expect(stateObj.reset).not.toHaveBeenCalled();
        }
      });
    });

    it('should reset all slices to initial state', () => {
      // Arrange
      const state = useTestRootStore.getState();

      // Modify some state
      if (state.parameterPointsProgramActions) {
        state.parameterPointsProgramActions.setLoading(true);
      }
      if (state.permissionActions) {
        state.permissionActions.setHasRedeemed(true);
      }

      // Act
      cardPlaceStoreCleanup();

      // Assert - verify reset was called (state won't actually reset because we mocked it)
      Object.keys(resetMocks).forEach((key) => {
        expect(resetMocks[key]).toHaveBeenCalled();
      });
    });
  });

  describe('IGNORE_CACHE_CLEAR behavior', () => {
    it('should skip action objects in IGNORE_CACHE_CLEAR set', () => {
      // Arrange
      const state = useTestRootStore.getState();
      const actionKeys = Object.keys(state).filter((key) => key.endsWith('Actions'));

      if (actionKeys.length === 0) {
        throw new Error('No action objects found in test store');
      }

      const keyToIgnore = actionKeys[0];
      IGNORE_CACHE_CLEAR.add(keyToIgnore);

      // Act
      cardPlaceStoreCleanup();

      // Assert
      expect(resetMocks[keyToIgnore]).not.toHaveBeenCalled();

      // Other action objects should still be reset
      actionKeys
        .filter((key) => key !== keyToIgnore)
        .forEach((key) => {
          expect(resetMocks[key]).toHaveBeenCalledTimes(1);
        });
    });

    it('should skip multiple action objects in IGNORE_CACHE_CLEAR set', () => {
      // Arrange
      const state = useTestRootStore.getState();
      const actionKeys = Object.keys(state).filter((key) => key.endsWith('Actions'));

      if (actionKeys.length < 2) {
        // If we only have one action, just test that it gets ignored
        const keyToIgnore = actionKeys[0];
        IGNORE_CACHE_CLEAR.add(keyToIgnore);

        // Act
        cardPlaceStoreCleanup();

        // Assert
        expect(resetMocks[keyToIgnore]).not.toHaveBeenCalled();
        return;
      }

      const keysToIgnore = actionKeys.slice(0, 2);
      keysToIgnore.forEach((key) => IGNORE_CACHE_CLEAR.add(key));

      // Act
      cardPlaceStoreCleanup();

      // Assert
      keysToIgnore.forEach((key) => {
        expect(resetMocks[key]).not.toHaveBeenCalled();
      });

      // Other action objects should still be reset
      actionKeys
        .filter((key) => !keysToIgnore.includes(key))
        .forEach((key) => {
          expect(resetMocks[key]).toHaveBeenCalledTimes(1);
        });
    });
  });

  describe('Error handling', () => {
    it('should log error when action object is missing reset method', () => {
      // Arrange
      const mockState = {
        someActions: {
          // Missing reset method
          setData: jest.fn(),
        },
        someState: {
          data: null,
        },
      };

      // Mock getState to return our custom state
      jest.spyOn(useTestRootStore, 'getState').mockReturnValue(mockState as any);

      // Act
      cardPlaceStoreCleanup();

      // Assert
      expect(consoleErrorSpy).toHaveBeenCalledWith(
        'useRootStore.getState().someActions is missing a "reset" action.'
      );
    });

    it('should log error and continue when reset() throws an error', () => {
      // Arrange
      const state = useTestRootStore.getState();
      const actionKeys = Object.keys(state).filter((key) => key.endsWith('Actions'));

      if (actionKeys.length === 0) {
        throw new Error('No action objects found in test store');
      }

      const errorKey = actionKeys[0];
      const error = new Error('Reset failed');
      resetMocks[errorKey].mockImplementation(() => {
        throw error;
      });

      // Act
      cardPlaceStoreCleanup();

      // Assert
      expect(consoleErrorSpy).toHaveBeenCalledWith(
        `Failed to run ${errorKey}.reset():`,
        error
      );

      // Other action objects should still be reset
      actionKeys
        .filter((key) => key !== errorKey)
        .forEach((key) => {
          expect(resetMocks[key]).toHaveBeenCalledTimes(1);
        });
    });

    it('should handle null action object gracefully', () => {
      // Arrange
      const mockState = {
        nullActions: null,
        validActions: {
          reset: jest.fn(),
        },
      };

      jest.spyOn(useTestRootStore, 'getState').mockReturnValue(mockState as any);

      // Act
      expect(() => cardPlaceStoreCleanup()).not.toThrow();

      // Assert
      expect(mockState.validActions.reset).toHaveBeenCalledTimes(1);
    });

    it('should handle undefined action object gracefully', () => {
      // Arrange
      const mockState = {
        undefinedActions: undefined,
        validActions: {
          reset: jest.fn(),
        },
      };

      jest.spyOn(useTestRootStore, 'getState').mockReturnValue(mockState as any);

      // Act
      expect(() => cardPlaceStoreCleanup()).not.toThrow();

      // Assert
      expect(mockState.validActions.reset).toHaveBeenCalledTimes(1);
    });

    it('should handle action object with non-function reset property', () => {
      // Arrange
      const mockState = {
        invalidActions: {
          reset: 'not a function',
        },
      };

      jest.spyOn(useTestRootStore, 'getState').mockReturnValue(mockState as any);

      // Act
      cardPlaceStoreCleanup();

      // Assert
      expect(consoleErrorSpy).toHaveBeenCalledWith(
        'useRootStore.getState().invalidActions is missing a "reset" action.'
      );
    });
  });

  describe('Multiple slices', () => {
    it('should reset multiple slices in correct order', () => {
      // Arrange
      const state = useTestRootStore.getState();
      const actionKeys = Object.keys(state).filter((key) => key.endsWith('Actions'));

      const callOrder: string[] = [];
      actionKeys.forEach((key) => {
        resetMocks[key].mockImplementation(() => {
          callOrder.push(key);
        });
      });

      // Act
      cardPlaceStoreCleanup();

      // Assert
      expect(callOrder).toHaveLength(actionKeys.length);
      // Verify all actions were called
      actionKeys.forEach((key) => {
        expect(callOrder).toContain(key);
      });
    });

    it('should continue resetting other slices even if one fails', () => {
      // Arrange
      const mockState = {
        firstActions: {
          reset: jest.fn(() => {
            throw new Error('First reset failed');
          }),
        },
        secondActions: {
          reset: jest.fn(),
        },
        thirdActions: {
          reset: jest.fn(() => {
            throw new Error('Third reset failed');
          }),
        },
      };

      jest.spyOn(useTestRootStore, 'getState').mockReturnValue(mockState as any);

      // Act
      cardPlaceStoreCleanup();

      // Assert
      expect(mockState.firstActions.reset).toHaveBeenCalledTimes(1);
      expect(mockState.secondActions.reset).toHaveBeenCalledTimes(1);
      expect(mockState.thirdActions.reset).toHaveBeenCalledTimes(1);
      expect(consoleErrorSpy).toHaveBeenCalledTimes(2);
    });
  });

  describe('Edge cases', () => {
    it('should handle empty store state', () => {
      // Arrange
      jest.spyOn(useTestRootStore, 'getState').mockReturnValue({} as any);

      // Act & Assert
      expect(() => cardPlaceStoreCleanup()).not.toThrow();
      expect(consoleErrorSpy).not.toHaveBeenCalled();
    });

    it('should only process keys ending with "Actions"', () => {
      // Arrange
      const mockState = {
        // Should be processed
        userActions: {
          reset: jest.fn(),
        },
        authActions: {
          reset: jest.fn(),
        },
        // Should NOT be processed (doesn't end with Actions)
        user: { name: 'test' },
        auth: { token: 'abc' },
        actionHelper: { reset: jest.fn() }, // Contains 'action' but doesn't end with 'Actions'
        myActionsHelper: { reset: jest.fn() }, // Contains 'Actions' but doesn't end with it
      };

      jest.spyOn(useTestRootStore, 'getState').mockReturnValue(mockState as any);

      // Act
      cardPlaceStoreCleanup();

      // Assert
      expect(mockState.userActions.reset).toHaveBeenCalledTimes(1);
      expect(mockState.authActions.reset).toHaveBeenCalledTimes(1);
      expect(mockState.actionHelper.reset).not.toHaveBeenCalled();
      expect(mockState.myActionsHelper.reset).not.toHaveBeenCalled();
    });
  });

  describe('IGNORE_CACHE_CLEAR Set', () => {
    it('should export IGNORE_CACHE_CLEAR as a Set', () => {
      expect(IGNORE_CACHE_CLEAR).toBeInstanceOf(Set);
    });

    it('should start with empty IGNORE_CACHE_CLEAR set', () => {
      // Clear before checking
      IGNORE_CACHE_CLEAR.clear();
      expect(IGNORE_CACHE_CLEAR.size).toBe(0);
    });

    it('should allow adding items to IGNORE_CACHE_CLEAR', () => {
      IGNORE_CACHE_CLEAR.clear();
      IGNORE_CACHE_CLEAR.add('testActions');
      expect(IGNORE_CACHE_CLEAR.has('testActions')).toBe(true);
    });

    it('should allow removing items from IGNORE_CACHE_CLEAR', () => {
      IGNORE_CACHE_CLEAR.clear();
      IGNORE_CACHE_CLEAR.add('testActions');
      IGNORE_CACHE_CLEAR.delete('testActions');
      expect(IGNORE_CACHE_CLEAR.has('testActions')).toBe(false);
    });
  });
});

