      expect(newState.additionalCard.name).toBe('');

      // permission should NOT be reset (in ignore list)
      expect(newState.permission.hasRedeemed).toBe(true);

      expect(consoleErrorSpy).not.toHaveBeenCalled();
    });

    it('should skip multiple slices in IGNORE_CACHE_CLEAR', () => {
      const state = useTestRootStore.getState();

      // Add multiple slices to ignore list
      IGNORE_CACHE_CLEAR.add('permissionActions');
      IGNORE_CACHE_CLEAR.add('additionalCardActions');

      // Set non-initial values
      state.parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.ERROR);
      state.permissionActions.setHasRedeemed(true);
      state.additionalCardActions.setName('Test User');

      // Call cleanup
      cardPlaceStoreCleanup();

      const newState = useTestRootStore.getState();

