      const allKeys = Object.keys(state);
      const actionKeys = allKeys.filter(key => key.endsWith('Actions'));
      const stateKeys = allKeys.filter(key => !key.endsWith('Actions'));

      // Verify state keys exist but weren't processed
      expect(stateKeys.length).toBeGreaterThan(0);
