      expect(actionKeys).toContain('parameterPointsProgramActions');
      expect(actionKeys).toContain('permissionActions');
      expect(actionKeys).toContain('additionalCardActions');

      paramResetSpy.mockRestore();
      permResetSpy.mockRestore();
      addlCardResetSpy.mockRestore();
    });

