      // Ensure IGNORE_CACHE_CLEAR is empty
      IGNORE_CACHE_CLEAR.clear();

      // Set non-initial values
      state.parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.ERROR);

      // Call cleanup
      cardPlaceStoreCleanup();

      const newState = useTestRootStore.getState();

      // Should reset normally
      expect(newState.parameterPointsProgram.status).toBe(ParameterPointsProgramStatus.IDLE);
      expect(consoleErrorSpy).not.toHaveBeenCalled();
    });
  });

  describe('Integration', () => {
    it('should reset all slices when called multiple times', () => {
      const state = useTestRootStore.getState();

      // First cleanup cycle
      state.parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.ERROR);
      cardPlaceStoreCleanup();

      let newState = useTestRootStore.getState();
      expect(newState.parameterPointsProgram.status).toBe(ParameterPointsProgramStatus.IDLE);

      // Second cleanup cycle
      state.permissionActions.setHasRedeemed(true);
      cardPlaceStoreCleanup();

      newState = useTestRootStore.getState();
      expect(newState.permission.hasRedeemed).toBeNull();

      // Third cleanup cycle
      state.additionalCardActions.setName('Test');
      cardPlaceStoreCleanup();

      newState = useTestRootStore.getState();
      expect(newState.additionalCard.name).toBe('');

      expect(consoleErrorSpy).not.toHaveBeenCalled();
    });

    it('should work correctly after IGNORE_CACHE_CLEAR is modified', () => {
      const state = useTestRootStore.getState();

      // First call with empty ignore list
      state.parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.ERROR);
      state.permissionActions.setHasRedeemed(true);

      cardPlaceStoreCleanup();

      let newState = useTestRootStore.getState();
      expect(newState.parameterPointsProgram.status).toBe(ParameterPointsProgramStatus.IDLE);
      expect(newState.permission.hasRedeemed).toBeNull();

      // Set values again and add to ignore list
      state.parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.ERROR);
      state.permissionActions.setHasRedeemed(true);
      IGNORE_CACHE_CLEAR.add('permissionActions');

      cardPlaceStoreCleanup();

      newState = useTestRootStore.getState();
      expect(newState.parameterPointsProgram.status).toBe(ParameterPointsProgramStatus.IDLE);
      expect(newState.permission.hasRedeemed).toBe(true); // Should be ignored

      // Clear ignore list and run again
      IGNORE_CACHE_CLEAR.clear();
      cardPlaceStoreCleanup();

      newState = useTestRootStore.getState();
      expect(newState.permission.hasRedeemed).toBeNull(); // Should be reset now

      expect(consoleErrorSpy).not.toHaveBeenCalled();
    });
  });
});

